diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..0e40b9922efb 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3011,14 +3011,47 @@ struct DecomposedSelect {
   Value *FalseVal = nullptr;
 };
 } // namespace
+/// Fold a select of symmetric selects:
+///   %sel1 = select i1 %c1, i32 %a, i32 %b
+///   %sel2 = select i1 %c1, i32 %b, i32 %a
+///   %ret = select i1 %c2, i32 %sel1, i32 %sel2
+/// <-->
+///   %xor = xor i1 %c1, %c2
+///   %ret = select i1 %xor, i32 %b, i32 %a
+static Instruction *foldSelectOfSymmetricSelects(SelectInst &SI,
+                                                  InstCombiner::BuilderTy &Builder) {
+  // Match: select i1 %c2, i32 %sel1, i32 %sel2
+  Value *Cond, *TrueVal, *FalseVal;
+  if (!match(&SI, m_Select(m_Value(Cond), m_Value(TrueVal), m_Value(FalseVal))))
+    return nullptr;
+
+  // Match %sel1 = select i1 %c1, i32 %a, i32 %b
+  Value *InnerCond, *TrueTrueVal, *TrueFalseVal;
+  if (!match(TrueVal, m_OneUse(m_Select(m_Value(InnerCond), m_Value(TrueTrueVal),
+                                         m_Value(TrueFalseVal)))))
+    return nullptr;
+
+  // The inner and outer conditions must be the same type for XOR
+  if (InnerCond->getType() != Cond->getType())
+    return nullptr;
+
+  // Match %sel2 = select i1 %c1, i32 %b, i32 %a (swapped arms, same condition)
+  Value *FalseTrueVal, *FalseFalseVal;
+  if (!match(FalseVal, m_OneUse(m_Select(m_Specific(InnerCond), m_Value(FalseTrueVal),
+                                          m_Value(FalseFalseVal)))))
+    return nullptr;
+
+  // Check if the operands are symmetric: sel1 has (a, b), sel2 has (b, a)
+  if (TrueTrueVal != FalseFalseVal || TrueFalseVal != FalseTrueVal)
+    return nullptr;
+
+  // Transform to: select (xor c1, c2), b, a
+  Value *XorCond = Builder.CreateXor(InnerCond, Cond);
+  return SelectInst::Create(XorCond, TrueFalseVal, TrueTrueVal);
+}

 /// Look for patterns like
-///   %outer.cond = select i1 %inner.cond, i1 %alt.cond, i1 false
-///   %inner.sel = select i1 %inner.cond, i8 %inner.sel.t, i8 %inner.sel.f
-///   %outer.sel = select i1 %outer.cond, i8 %outer.sel.t, i8 %inner.sel
-/// and rewrite it as
-///   %inner.sel = select i1 %cond.alternative, i8 %sel.outer.t, i8 %sel.inner.t
-///   %sel.outer = select i1 %cond.inner, i8 %inner.sel, i8 %sel.inner.f
+/// Look for patterns like
 static Instruction *foldNestedSelects(SelectInst &OuterSelVal,
                                       InstCombiner::BuilderTy &Builder) {
   // We must start with a `select`.
@@ -3990,6 +4023,9 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *I = foldNestedSelects(SI, Builder))
     return I;

+  if (Instruction *I = foldSelectOfSymmetricSelects(SI, Builder))
+    return I;
+
   // Match logical variants of the pattern,
   // and transform them iff that gets rid of inversions.
   //   (~x) | y  -->  ~(x & (~y))

log.source_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c1, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

